```c
static SECP256K1_INLINE void swap64(unsigned char *a, unsigned char *b, size_t len) {
    unsigned char tmp[64];
    VERIFY_CHECK(len <= 64);
    memcpy(tmp, a, len);
    memmove(a, b, len);
    memcpy(b, tmp, len);
}

static SECP256K1_INLINE void swap(unsigned char *arr, unsigned char *a, size_t stride) {
    unsigned char *a = arr + i*stride;
    unsigned char *b = arr + j*stride;
    size_t len = stride;
    while (64 < len) {
        swap64(a + (len - 64), b + (len - 64), 64);
        len -= 64;
    }
    swap64(a, b, len);
}
```

